mapper.select:
SELECT id, sender, receiver AS friendCode, content, type, read_state as readState, revoked, revoked_at AS revokedAt, create_time AS createTime FROM chat_message
revoked = 0 AND ( (sender = #{currentUser} AND receiver = #{friendCode}) OR (sender = #{friendCode} AND receiver = #{currentUser}) )
AND id < #{lastId}
AND type = #{type}
ORDER BY id DESC
LIMIT #{pageSize}
